(
    E'klaus-schulte-sankeyfunnelincomestatement-microsoftq1fy23',
    E'Sankey Funnel Income Statement',
    E'Sankey Funnel Income Statement',
    E'sankey',
    E'advanced',
    30,
    E'https://public.tableau.com/views/SankeyFunnelIncomeStatement/MicrosoftQ1FY23',
